// Parse all 17 analysis fields — supports BOTH formats:
// 1) ElevenLabs post_call_transcription (nested data_collection_results)
// 2) Flat format from summary/route.ts

const raw = $input.first().json.body ?? $input.first().json;
const isElevenLabs = raw.type === 'post_call_transcription';

// Helper: extract field from data_collection_results (with trimmed key fallback)
function getField(dcr, fieldName) {
  if (!dcr) return null;
  if (dcr[fieldName]) return dcr[fieldName].value;
  const key = Object.keys(dcr).find(k => k.trim() === fieldName);
  return key ? dcr[key].value : null;
}

let body;
if (isElevenLabs) {
  const dcr = raw.data?.analysis?.data_collection_results || {};
  body = {
    anrufer_name: getField(dcr, 'anrufer_name') || '',
    anrufer_email: getField(dcr, 'anrufer_email') || '',
    anrufer_telefon: getField(dcr, 'anrufer_telefon') || '',
    sprache: getField(dcr, 'sprache') || 'de',
    kategorie: getField(dcr, 'kategorie') || 'Allgemein',
    thema: getField(dcr, 'thema') || 'Allgemein',
    anliegen: getField(dcr, 'anliegen') || '',
    interessiertes_paket: getField(dcr, 'interessiertes_paket') || 'keines',
    kaufbereitschaft: getField(dcr, 'kaufbereitschaft') || 'unklar',
    einwand: getField(dcr, 'einwand') || 'keiner',
    geburtsdatum_genannt: getField(dcr, 'geburtsdatum_genannt'),
    status: getField(dcr, 'status') || 'FAQ_beantwortet',
    termin_gebucht: getField(dcr, 'termin_gebucht'),
    termin_datum: getField(dcr, 'termin_datum') || '',
    follow_up_noetig: getField(dcr, 'follow_up_noetig'),
    naechster_schritt: getField(dcr, 'naechster_schritt') || 'Keine_Aktion',
    zusammenfassung: getField(dcr, 'zusammenfassung') || ''
  };
} else {
  body = raw;
}

const now = new Date();
const id = `VA-${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}-${String(now.getHours()).padStart(2,'0')}${String(now.getMinutes()).padStart(2,'0')}${String(now.getSeconds()).padStart(2,'0')}`;

// Convert booleans to Ja/Nein for German spreadsheet
const jaOderNein = (val) => val === true || val === 'true' ? 'Ja' : 'Nein';

return [{
  json: {
    ID: id,
    anrufer_name: body.anrufer_name || '',
    anrufer_email: body.anrufer_email || '',
    anrufer_telefon: body.anrufer_telefon || '',
    sprache: body.sprache || 'de',
    kategorie: body.kategorie || 'Allgemein',
    thema: body.thema || 'Allgemein',
    anliegen: body.anliegen || '',
    interessiertes_paket: body.interessiertes_paket || 'keines',
    kaufbereitschaft: body.kaufbereitschaft || 'unklar',
    einwand: body.einwand || 'keiner',
    geburtsdatum_genannt: jaOderNein(body.geburtsdatum_genannt),
    status: body.status || 'FAQ_beantwortet',
    termin_gebucht: jaOderNein(body.termin_gebucht),
    termin_datum: body.termin_datum || '',
    follow_up_noetig: jaOderNein(body.follow_up_noetig),
    naechster_schritt: body.naechster_schritt || 'Keine_Aktion',
    zusammenfassung: body.zusammenfassung || ''
  }
}];
